        })()""".stripMargin.trim,
      expected = """console.log((new class extends(function(foo_base) {
            return class extends foo_base {};
        }(function(bar_base) {
            return class extends bar_base {};
        }(Array))){}).concat([ "PASS" ])[0])""".stripMargin.trim,
      options = AllOff.copy(
        evaluate = true,
        inline = InlineLevel.InlineFull,
        passes = 1,
        reduceFuncs = true,
        reduceVars = true,
        sideEffects = true,
        unused = true
      )
    )
  }

