      options = AllOff.copy(
        inline = InlineLevel.InlineFull,
        toplevel = ToplevelConfig(funcs = true, vars = true)
      )
    )
  }

  // =========================================================================
  // issue_308
  // =========================================================================
  test("issue_308".fail) {
    assertCompresses(
      input = """exports.withStyles = withStyles;

        function _inherits(superClass) {
            if (typeof superClass !== "function") {
                throw new TypeError("Super expression must be a function, not " + typeof superClass);
            }
            Object.create(superClass);
        }

        function withStyles() {
            var a = EXTERNAL();
            return function(_a) {
                _inherits(_a);
                function d() {}
            }(a);
        }""".stripMargin.trim,
      expected = """exports.withStyles = function () {
            !function (superClass) {
                if ("function" != typeof superClass)
                    throw new TypeError("Super expression must be a function, not " + typeof superClass);
                Object.create(superClass);
            }(EXTERNAL());
        }""".stripMargin.trim,
      options = AllOff.copy(
        passes = 4,
        toplevel = ToplevelConfig(funcs = true, vars = true)
      )
    )
  }

